<!doctype html>
<html><head><meta charset="utf-8"><title>Asset Declaration</title><style>body{font-family:Arial,sans-serif;color:#111;margin:36px}.doc{max-width:820px;margin:auto}.head{border-bottom:2px solid #111;padding-bottom:16px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:24px 0}.box{border:1px solid #ccc;padding:12px}.terms{line-height:1.7;margin:28px 0}.sign{display:grid;grid-template-columns:1fr 1fr;gap:48px;margin-top:80px}.line{border-top:1px solid #111;padding-top:8px}@media print{button{display:none}}</style></head>
<body onload="window.print()"><div class="doc"><button onclick="window.print()">Print</button><div class="head"><h1>Asset Declaration Form</h1><strong>{{ $declaration->declaration_number }}</strong></div><div class="grid"><div class="box"><strong>Employee</strong><br>{{ $declaration->assignment?->employee?->name_en }}<br><span dir="rtl">{{ $declaration->assignment?->employee?->name_ar }}</span><br>{{ $declaration->assignment?->employee?->employee_code }}</div><div class="box"><strong>Asset</strong><br>{{ $declaration->assignment?->asset?->asset_tag }} - {{ $declaration->assignment?->asset?->name }}<br>Serial: {{ $declaration->assignment?->asset?->serial_number ?: '-' }}<br>Brand: {{ $declaration->assignment?->asset?->brand?->name ?? '-' }}</div></div><p class="terms">{{ $declaration->terms }}</p><div class="sign"><div class="line">Employee Signature</div><div class="line">Company Representative</div></div></div></body></html>
